"""Claude Code platform-specific models and state derivation."""

from pydantic import BaseModel, field_validator

# State priority — lower number = higher priority.
_STATE_PRIORITY: dict[str, int] = {
    "permission_required": 0,
    "awaiting_input": 1,
    "working": 2,
    "ready": 3,
    "idle": 4,
}

# Static event-to-state mapping for events that don't depend on tool_name.
_EVENT_STATE_MAP: dict[str, str] = {
    "UserPromptSubmit": "working",
    "PostToolUse": "working",
    "PostToolUseFailure": "working",
    "Stop": "idle",
    "StopFailure": "idle",
}


class ClaudeHookPayload(BaseModel):
    """Incoming hook event from Claude Code."""

    session_id: str
    hook_event_name: str
    tool_name: str = ""
    agent_id: str = ""
    agent_type: str = ""
    cwd: str = ""
    source_system: str = ""

    @field_validator("session_id")
    @classmethod
    def session_id_not_empty(cls, v: str) -> str:
        """Reject empty session_id to prevent orphaned events."""
        if not v:
            raise ValueError("session_id must not be empty")
        return v


