def derive_state(
    event_name: str,
    *,
    tool_name: str = "",
    agent_id: str = "",
) -> str | None:
    """Derive a state string from a raw hook event.

    Returns None for events that don't map to a state (e.g. SubagentStop,
    SessionEnd). This mirrors claude-dashboard's map_event_to_state but
    returns strings instead of enum values.
    """
    if event_name == "PreToolUse":
        if tool_name == "AskUserQuestion":
            return "awaiting_input"
        return "working"

    if event_name == "PermissionRequest":
        if tool_name == "AskUserQuestion":
            return "awaiting_input"
        return "permission_required"

    state = _EVENT_STATE_MAP.get(event_name)
    if state is None and agent_id and event_name != "SubagentStop":
        return "working"
    return state


def compute_effective_state(
    session_state: str | None,
    agent_states: list[str | None],
) -> str | None:
    """Compute the highest-priority state across session + agents.

    Returns the state with the lowest priority number (highest urgency).
    Returns None if no states are available.
    """
    all_states = [session_state] + agent_states
    best: str | None = None
    best_priority = 999

    for state in all_states:
        if state is None:
            continue
        priority = _STATE_PRIORITY.get(state, 999)
        if priority < best_priority:
            best = state
            best_priority = priority

    return best
